window.QUIZ_DATA = [
    // ── REST ──
    { cat: "REST", q: "What does REST stand for?", opts: ["Representational State Transfer", "Remote State Transfer", "Representational Service Transfer", "Real-time State Transfer"], ans: 0, exp: "REST stands for Representational State Transfer, an architectural style for designing networked applications proposed by Roy Fielding in his 2000 doctoral dissertation." },
    { cat: "REST", q: "Which HTTP method is idempotent and used to update a resource completely?", opts: ["POST", "PUT", "PATCH", "CONNECT"], ans: 1, exp: "PUT replaces the entire resource with the supplied representation and is idempotent — calling it multiple times produces the same result." },
    { cat: "REST", q: "Which HTTP method is typically used to partially update a resource?", opts: ["PUT", "PATCH", "POST", "DELETE"], ans: 1, exp: "PATCH applies a partial modification to a resource, unlike PUT which replaces the whole resource." },
    { cat: "REST", q: "What HTTP status code indicates a resource was successfully created?", opts: ["200", "201", "204", "202"], ans: 1, exp: "201 Created indicates the request succeeded and a new resource was created as a result, typically returned by POST requests." },
    { cat: "REST", q: "What HTTP status code means 'No Content'?", opts: ["200", "202", "204", "304"], ans: 2, exp: "204 No Content indicates the server successfully processed the request but is not returning any content in the response body." },
    { cat: "REST", q: "In REST, what does 'statelessness' mean?", opts: ["The server never crashes", "Each request contains all info needed to process it, with no client context stored on the server", "The client cannot store state", "Responses never change"], ans: 1, exp: "Statelessness means every request from a client must contain all the information needed to understand and process it; the server does not store any client session state between requests." },
    { cat: "REST", q: "Which HTTP status code range indicates client errors?", opts: ["1xx", "3xx", "4xx", "5xx"], ans: 2, exp: "4xx status codes indicate that the client appears to have made an error, such as 404 Not Found or 400 Bad Request." },
    { cat: "REST", q: "Which HTTP status code range indicates server errors?", opts: ["3xx", "4xx", "5xx", "2xx"], ans: 2, exp: "5xx status codes indicate the server failed to fulfill a valid request, such as 500 Internal Server Error or 503 Service Unavailable." },
    { cat: "REST", q: "What does HATEOAS stand for in REST architecture?", opts: ["Hypertext As The Engine Of Application State", "Hyper API Transfer Engine Over Application Services", "High Availability Transfer Engine Over App State", "Hypermedia Application Type Engine Of State"], ans: 0, exp: "HATEOAS (Hypertext As The Engine Of Application State) is a REST constraint where clients interact with the application entirely through hypermedia links provided dynamically by server responses." },
    { cat: "REST", q: "Which HTTP method is safe and idempotent, used purely to retrieve data?", opts: ["GET", "POST", "PUT", "PATCH"], ans: 0, exp: "GET requests retrieve data and should have no side effects (safe), and repeating the same GET request yields the same result (idempotent)." },
    { cat: "REST", q: "What HTTP status code represents 'Unauthorized'?", opts: ["400", "401", "403", "404"], ans: 1, exp: "401 Unauthorized indicates the request lacks valid authentication credentials for the target resource." },
    { cat: "REST", q: "What HTTP status code represents 'Forbidden'?", opts: ["401", "402", "403", "405"], ans: 2, exp: "403 Forbidden means the server understood the request but refuses to authorize it, typically because the client lacks permission even though it may be authenticated." },
    { cat: "REST", q: "What is the purpose of the HTTP 'ETag' header?", opts: ["To specify content type", "To enable caching by providing a resource version identifier", "To set cookies", "To redirect requests"], ans: 1, exp: "An ETag is an opaque identifier assigned by a server to a specific version of a resource, used for cache validation and conditional requests." },
    { cat: "REST", q: "Which header is commonly used to specify the format of the request body in a REST API?", opts: ["Accept", "Content-Type", "Content-Length", "Content-Encoding"], ans: 1, exp: "The Content-Type header indicates the media type of the resource being sent, such as application/json." },
    { cat: "REST", q: "Which header tells the server what response formats the client can accept?", opts: ["Content-Type", "Accept", "Accept-Encoding", "Allow"], ans: 1, exp: "The Accept header lets the client specify which content types it is able to understand in the response, e.g. application/json." },
    { cat: "REST", q: "What does idempotency mean for an HTTP method?", opts: ["The method always succeeds", "Multiple identical requests have the same effect as a single request", "The method is cached", "The method requires authentication"], ans: 1, exp: "An idempotent method produces the same result no matter how many times the identical request is repeated, such as PUT or DELETE." },
    { cat: "REST", q: "Is the POST method idempotent by default?", opts: ["Yes, always", "No, repeated POSTs may create multiple resources", "Only with query parameters", "Only over HTTPS"], ans: 1, exp: "POST is not idempotent by default — submitting the same POST request multiple times typically creates multiple new resources." },
    { cat: "REST", q: "What HTTP status code indicates a redirect that preserves the request method?", opts: ["301", "302", "307", "303"], ans: 2, exp: "307 Temporary Redirect tells the client to repeat the request at a new URI using the same HTTP method, unlike 302 which historically allowed method changes." },
    { cat: "REST", q: "What is the typical purpose of versioning a REST API (e.g. /v1/users)?", opts: ["To improve performance", "To allow breaking changes without disrupting existing clients", "To enable caching", "To reduce payload size"], ans: 1, exp: "API versioning lets providers introduce breaking changes in a new version while existing clients continue using the older, stable version." },
    { cat: "REST", q: "Which of these is NOT a common way to version a REST API?", opts: ["URI versioning (/v1/resource)", "Header versioning (Accept-Version)", "Query parameter versioning (?version=1)", "Changing the TCP port for each version"], ans: 3, exp: "Changing TCP ports is not a standard REST versioning strategy; common approaches are URI path, custom headers, or query parameters." },
    { cat: "REST", q: "What does the term 'resource' mean in REST?", opts: ["A server file", "Any piece of information that can be named and addressed via a URI", "A database table", "A caching layer"], ans: 1, exp: "In REST, a resource is any piece of information that can be named — a document, image, collection, or service — and is identified by a URI." },
    { cat: "REST", q: "What does CRUD stand for in the context of REST APIs?", opts: ["Create, Read, Update, Delete", "Connect, Retrieve, Use, Drop", "Create, Retrieve, Use, Define", "Compute, Read, Upload, Distribute"], ans: 0, exp: "CRUD refers to the four basic operations — Create, Read, Update, Delete — typically mapped to POST, GET, PUT/PATCH, and DELETE in REST APIs." },
    { cat: "REST", q: "What does HTTP status 429 indicate?", opts: ["Not Found", "Too Many Requests", "Conflict", "Gateway Timeout"], ans: 1, exp: "429 Too Many Requests indicates the client has sent too many requests in a given time, used for rate limiting." },
    { cat: "REST", q: "What is the purpose of a 'Location' header in REST responses?", opts: ["To indicate the client's geographic location", "To specify the URI of a newly created resource (often with 201) or redirect target (with 3xx)", "To specify caching rules", "To specify content language"], ans: 1, exp: "The Location header indicates the URI to redirect to, or, for a 201 Created response, the URI of the newly created resource." },
    { cat: "REST", q: "What does the term 'richardson maturity model' describe?", opts: ["A database normalization model", "A model that grades the maturity of a REST API across levels 0-3", "A caching strategy", "A security framework"], ans: 1, exp: "The Richardson Maturity Model grades REST API design from Level 0 (single endpoint, RPC-style) up to Level 3 (full HATEOAS hypermedia controls)." },
    { cat: "REST", q: "Which HTTP status code indicates a conflict with the current state of a resource?", opts: ["400", "404", "409", "422"], ans: 2, exp: "409 Conflict indicates the request could not be completed due to a conflict with the current state of the target resource, such as a duplicate entry." },
    { cat: "REST", q: "What is the role of OpenAPI (formerly Swagger) in REST development?", opts: ["A runtime for executing REST calls", "A specification format for describing REST API structure and documentation", "A database query language", "A load balancer"], ans: 1, exp: "OpenAPI is a specification for describing REST APIs in a machine-readable format, enabling documentation, client generation, and validation tooling." },
    { cat: "REST", q: "What does 'Content-Length' header specify?", opts: ["The number of resources returned", "The size of the request/response body in bytes", "The maximum allowed payload", "The compression ratio"], ans: 1, exp: "Content-Length specifies the size of the message body in bytes, allowing the receiver to know when the body ends." },
    { cat: "REST", q: "What is the purpose of pagination in a REST API listing endpoint?", opts: ["To encrypt data", "To break large result sets into smaller chunks for efficiency", "To enable caching only", "To validate authentication"], ans: 1, exp: "Pagination divides large collections into pages, reducing payload size and improving performance for both client and server." },
    { cat: "REST", q: "What does the OPTIONS HTTP method typically return?", opts: ["The resource body", "The communication options/allowed methods for a resource", "A redirect", "An authentication token"], ans: 1, exp: "The OPTIONS method requests information about the communication options available for a target resource, commonly used in CORS preflight requests." },
    { cat: "REST", q: "What is a CORS preflight request?", opts: ["A GET request to warm the cache", "An OPTIONS request sent automatically by the browser to check if a cross-origin request is permitted", "A DNS lookup", "A TCP handshake"], ans: 1, exp: "Browsers automatically send an OPTIONS preflight request before certain cross-origin requests to verify the server permits the actual request method and headers." },
    { cat: "REST", q: "Which is a best practice for naming REST resource URIs?", opts: ["Use verbs like /getUser", "Use plural nouns like /users", "Use random hashes", "Use only query parameters"], ans: 1, exp: "REST URIs conventionally use plural nouns to represent collections of resources (e.g. /users), letting HTTP methods convey the action rather than verbs in the path." },
    { cat: "REST", q: "What does HTTP status code 422 typically indicate?", opts: ["Unauthorized", "Unprocessable Entity — request is well-formed but semantically invalid", "Not Found", "Method Not Allowed"], ans: 1, exp: "422 Unprocessable Entity means the server understands the content type and syntax of the request but was unable to process the contained instructions, often due to validation errors." },
    { cat: "REST", q: "What is idempotency-key used for in REST APIs?", opts: ["Encrypting passwords", "Allowing safe retries of non-idempotent operations like POST without duplicate side effects", "Compressing payloads", "Routing requests"], ans: 1, exp: "An idempotency key, sent by the client, lets the server detect and ignore duplicate retried requests, making operations like payments safe to retry." },
    { cat: "REST", q: "What does 'Cache-Control: no-store' instruct?", opts: ["Cache the response indefinitely", "Do not cache the response at all", "Cache only on the client", "Compress before caching"], ans: 1, exp: "Cache-Control: no-store instructs that the response must not be stored in any cache, used for sensitive data." },

    // ── GRAPHQL ──
    { cat: "GraphQL", q: "Who originally developed GraphQL?", opts: ["Google", "Facebook (Meta)", "Microsoft", "Netflix"], ans: 1, exp: "GraphQL was developed internally by Facebook in 2012 and open-sourced in 2015." },
    { cat: "GraphQL", q: "What is the primary advantage of GraphQL over REST regarding data fetching?", opts: ["It uses less memory on the server", "Clients can request exactly the fields they need, avoiding over-fetching and under-fetching", "It only works over WebSockets", "It eliminates the need for a server"], ans: 1, exp: "GraphQL lets clients specify exactly which fields they want in a single query, solving the over-fetching and under-fetching problems common with fixed REST endpoints." },
    { cat: "GraphQL", q: "What are the three root operation types in GraphQL?", opts: ["Get, Post, Delete", "Query, Mutation, Subscription", "Read, Write, Stream", "Fetch, Update, Listen"], ans: 1, exp: "GraphQL defines three root types: Query for reading data, Mutation for writing/modifying data, and Subscription for real-time updates." },
    { cat: "GraphQL", q: "What is used to define the shape of data in a GraphQL API?", opts: ["JSON Schema", "Schema Definition Language (SDL)", "XML DTD", "YAML"], ans: 1, exp: "GraphQL APIs are described using the Schema Definition Language (SDL), which defines types, fields, queries, and mutations." },
    { cat: "GraphQL", q: "In GraphQL, what is a 'resolver'?", opts: ["A function that returns data for a specific field in the schema", "A network proxy", "A caching mechanism", "A type validator only"], ans: 0, exp: "A resolver is a function attached to a schema field that is responsible for fetching/computing the data for that field when queried." },
    { cat: "GraphQL", q: "What does a GraphQL Mutation operation do?", opts: ["Only reads data", "Modifies server-side data (create, update, delete)", "Subscribes to real-time events", "Validates the schema"], ans: 1, exp: "Mutations are GraphQL operations used to modify data on the server, analogous to POST/PUT/PATCH/DELETE in REST." },
    { cat: "GraphQL", q: "How many endpoints does a typical GraphQL API expose?", opts: ["One per resource type", "Typically a single endpoint for all operations", "One per query", "Unlimited, one per field"], ans: 1, exp: "Unlike REST which uses multiple resource-based URLs, GraphQL typically exposes a single endpoint that handles all queries, mutations, and subscriptions." },
    { cat: "GraphQL", q: "What HTTP method is most commonly used to send GraphQL queries?", opts: ["GET only", "POST", "PUT", "DELETE"], ans: 1, exp: "GraphQL operations are most commonly sent via HTTP POST with the query in the request body, though GET is also supported for simple queries." },
    { cat: "GraphQL", q: "What GraphQL operation type enables real-time updates pushed from server to client?", opts: ["Query", "Mutation", "Subscription", "Fragment"], ans: 2, exp: "Subscriptions allow clients to receive real-time updates by maintaining a persistent connection (often via WebSockets) when specific events occur on the server." },
    { cat: "GraphQL", q: "What is the 'N+1 problem' in GraphQL?", opts: ["A versioning conflict", "Excessive database queries caused by resolving nested fields individually for each item in a list", "A type mismatch error", "A network timeout issue"], ans: 1, exp: "The N+1 problem occurs when resolving a list of items triggers one query per item for related data, resulting in N+1 total queries instead of a batched query." },
    { cat: "GraphQL", q: "What tool is commonly used to solve the N+1 problem in GraphQL?", opts: ["DataLoader", "Redux", "Webpack", "Express"], ans: 0, exp: "DataLoader is a utility that batches and caches database/API requests within a single execution cycle, mitigating the N+1 query problem." },
    { cat: "GraphQL", q: "What is a GraphQL 'fragment'?", opts: ["A part of the network packet", "A reusable unit of fields that can be shared across multiple queries", "An error type", "A caching strategy"], ans: 1, exp: "Fragments let developers define a reusable set of fields that can be included in multiple queries, reducing duplication." },
    { cat: "GraphQL", q: "What scalar types are built into GraphQL by default?", opts: ["Int, Float, String, Boolean, ID", "Number, Text, Bool, Key", "Integer, Decimal, Char, Flag, UUID", "Short, Long, Byte, Char"], ans: 0, exp: "GraphQL's default scalar types are Int, Float, String, Boolean, and ID." },
    { cat: "GraphQL", q: "What is the purpose of GraphQL 'introspection'?", opts: ["To encrypt the schema", "To allow clients to query the schema itself to discover available types and fields", "To validate JWT tokens", "To compress responses"], ans: 1, exp: "Introspection allows clients (and tools like GraphiQL) to query the GraphQL schema itself to discover what types, fields, and operations are available." },
    { cat: "GraphQL", q: "How are errors typically represented in a GraphQL response?", opts: ["Always as HTTP 4xx/5xx status codes", "In an 'errors' array alongside the 'data' field, often with HTTP 200", "As a thrown exception only", "Errors are not supported"], ans: 1, exp: "GraphQL responses typically return HTTP 200 with both a 'data' field and an 'errors' array describing any issues encountered during execution." },
    { cat: "GraphQL", q: "What is a GraphQL 'directive'?", opts: ["A network routing rule", "An annotation like @include or @skip that conditionally alters query execution", "A database index", "A caching header"], ans: 1, exp: "Directives such as @include and @skip are annotations attached to fields or fragments that change execution behavior based on variables." },
    { cat: "GraphQL", q: "What does the @deprecated directive in a GraphQL schema indicate?", opts: ["The field will be removed and clients should stop using it", "The field requires authentication", "The field is cached", "The field is read-only"], ans: 0, exp: "The @deprecated directive marks a schema field as deprecated, often with a reason, signaling that clients should migrate away from it." },
    { cat: "GraphQL", q: "What is 'over-fetching' in the context of APIs?", opts: ["Sending too many requests", "Receiving more data fields than the client actually needs", "Caching too aggressively", "Using too many HTTP headers"], ans: 1, exp: "Over-fetching happens when an API response contains more data than the client needs, common in fixed-shape REST responses; GraphQL avoids this by letting clients specify fields." },
    { cat: "GraphQL", q: "What is 'under-fetching' in the context of APIs?", opts: ["Receiving too much data", "Needing multiple round trips to gather all required data because a single endpoint doesn't return enough", "Using too little bandwidth", "Caching too little"], ans: 1, exp: "Under-fetching occurs when a single REST endpoint doesn't return all needed data, forcing the client to make multiple requests to different endpoints." },
    { cat: "GraphQL", q: "What is Apollo Client commonly used for?", opts: ["A GraphQL server framework", "A popular client library for managing GraphQL queries, caching, and state in frontend apps", "A database engine", "A WebSocket protocol"], ans: 1, exp: "Apollo Client is a widely used JavaScript library for executing GraphQL queries/mutations and managing local and remote state with caching." },
    { cat: "GraphQL", q: "What does GraphQL use to describe a custom object type with fields?", opts: ["interface", "type", "enum", "scalar"], ans: 1, exp: "The 'type' keyword in GraphQL SDL defines an object type with a set of named, typed fields." },
    { cat: "GraphQL", q: "What is a GraphQL 'interface'?", opts: ["A network socket", "An abstract type that defines a set of fields that implementing types must include", "A caching layer", "A database connector"], ans: 1, exp: "A GraphQL interface defines a set of fields that any implementing object type must include, supporting polymorphism in the schema." },
    { cat: "GraphQL", q: "What is a 'union type' in GraphQL?", opts: ["A type that combines fields from multiple types into one", "A type representing an object that could be one of several object types, without shared fields", "A scalar alias", "A database join"], ans: 1, exp: "A union type represents an object that could be one of several object types, and unlike interfaces, the member types need not share common fields." },
    { cat: "GraphQL", q: "How does GraphQL typically handle file uploads, since the base spec doesn't define them?", opts: ["Files cannot be uploaded with GraphQL", "Through community conventions like the multipart request specification", "Only via FTP", "Through TCP sockets directly"], ans: 1, exp: "Because the GraphQL spec doesn't natively define file uploads, the community-driven GraphQL multipart request specification is commonly used to handle them over HTTP." },
    { cat: "GraphQL", q: "What is 'schema stitching' in GraphQL?", opts: ["Combining multiple GraphQL schemas into a single unified schema", "Encrypting the schema", "Validating query syntax", "Compressing the schema file"], ans: 0, exp: "Schema stitching is a technique for merging multiple GraphQL schemas (often from different services) into one combined schema exposed to clients." },
    { cat: "GraphQL", q: "What is Apollo Federation used for?", opts: ["Load balancing TCP connections", "Composing a single GraphQL graph from multiple independently developed microservice subgraphs", "Encrypting GraphQL traffic", "Rate limiting REST APIs"], ans: 1, exp: "Apollo Federation is an architecture for combining multiple GraphQL services (subgraphs) into a single unified graph (supergraph) without manual schema stitching." },
    { cat: "GraphQL", q: "In GraphQL, what is a 'variable'?", opts: ["A global server config", "A way to pass dynamic values into a query/mutation instead of hardcoding them", "A type alias", "A cache key"], ans: 1, exp: "Variables allow dynamic values to be passed into GraphQL operations at execution time rather than being hardcoded into the query string." },
    { cat: "GraphQL", q: "What is the main downside of GraphQL's flexibility regarding caching?", opts: ["GraphQL cannot be cached at all", "Standard HTTP caching is harder because most requests use POST to a single endpoint", "It requires a database", "It cannot use CDNs ever"], ans: 1, exp: "Because GraphQL typically uses POST requests to a single URL, traditional HTTP caching (which relies on distinct GET URLs) is harder to apply, requiring custom caching strategies." },
    { cat: "GraphQL", q: "What does 'GraphiQL' refer to?", opts: ["A GraphQL hosting provider", "An in-browser IDE for writing, validating, and testing GraphQL queries", "A database migration tool", "A load testing tool"], ans: 1, exp: "GraphiQL is an interactive, in-browser IDE for exploring a GraphQL schema and writing/testing queries against it." },
    { cat: "GraphQL", q: "What is a 'query complexity' or 'query cost' analysis used for in GraphQL?", opts: ["To improve syntax highlighting", "To prevent overly expensive or deeply nested queries from overloading the server", "To generate documentation", "To version the schema"], ans: 1, exp: "Query complexity analysis assigns a cost to queries based on depth/field count to prevent malicious or accidental resource-exhausting queries." },

    // ── gRPC ──
    { cat: "gRPC", q: "What does gRPC stand for/originate from?", opts: ["Google Remote Procedure Call", "General Remote Procedure Call", "Global Remote Process Communication", "Grid Remote Procedure Call"], ans: 0, exp: "gRPC is a high-performance, open-source RPC framework originally developed by Google (the 'g' is recursively defined but commonly associated with Google)." },
    { cat: "gRPC", q: "What serialization format does gRPC use by default?", opts: ["JSON", "XML", "Protocol Buffers (protobuf)", "YAML"], ans: 2, exp: "gRPC uses Protocol Buffers (protobuf) by default as its interface definition language and binary serialization format, offering compact, fast serialization." },
    { cat: "gRPC", q: "Which HTTP version does gRPC require as its transport protocol?", opts: ["HTTP/1.0", "HTTP/1.1", "HTTP/2", "HTTP/3 only"], ans: 2, exp: "gRPC is built on top of HTTP/2, leveraging its multiplexing, header compression, and binary framing for efficient communication." },
    { cat: "gRPC", q: "What file extension is used for Protocol Buffer definition files?", opts: [".proto", ".pbuf", ".grpc", ".gpc"], ans: 0, exp: "Protocol Buffer service and message definitions are written in .proto files, which are then compiled into language-specific code." },
    { cat: "gRPC", q: "Which of these is a streaming mode supported by gRPC?", opts: ["Unary only", "Client streaming, server streaming, and bidirectional streaming", "Only server streaming", "gRPC does not support streaming"], ans: 1, exp: "gRPC supports four communication patterns: unary (single request/response), server streaming, client streaming, and bidirectional streaming." },
    { cat: "gRPC", q: "What is 'unary RPC' in gRPC?", opts: ["A call with multiple streamed responses", "A simple request-response call, like a traditional function call", "A call with no response", "A call that streams both directions"], ans: 1, exp: "Unary RPC is the simplest gRPC pattern: the client sends a single request and gets a single response back, similar to a normal function call." },
    { cat: "gRPC", q: "Why is gRPC generally faster than JSON-based REST APIs?", opts: ["It avoids TCP entirely", "It uses compact binary serialization (protobuf) and HTTP/2 multiplexing instead of verbose text-based JSON over HTTP/1.1", "It uses UDP", "It has no schema"], ans: 1, exp: "gRPC's binary protobuf encoding is more compact and faster to parse than text-based JSON, and HTTP/2 enables multiplexed streams over a single connection, reducing overhead." },
    { cat: "gRPC", q: "What is the role of a .proto file's 'service' definition?", opts: ["Defines a database schema", "Defines the RPC methods a gRPC service exposes along with their request/response message types", "Defines network routes", "Defines HTTP headers"], ans: 1, exp: "The 'service' block in a .proto file declares the RPC methods available, specifying input and output message types for each." },
    { cat: "gRPC", q: "Does gRPC support browser clients natively without any proxy?", opts: ["Yes, fully native in all browsers", "No, browsers can't natively make HTTP/2 trailer-based gRPC calls, so gRPC-Web with a proxy is typically used", "Only in Chrome", "Only with WebSockets"], ans: 1, exp: "Browsers cannot natively support all of gRPC's HTTP/2 features (like trailers), so gRPC-Web combined with a proxy (such as Envoy) is used to bridge browser clients to gRPC backends." },
    { cat: "gRPC", q: "What does 'IDL' stand for in the context of gRPC/Protocol Buffers?", opts: ["Internet Data Layer", "Interface Definition Language", "Internal Distribution Logic", "Indexed Data List"], ans: 1, exp: "IDL stands for Interface Definition Language; Protocol Buffers serve as gRPC's IDL for defining service contracts and message structures." },
    { cat: "gRPC", q: "What is a key benefit of strongly-typed contracts in gRPC via protobuf?", opts: ["Smaller hard drives", "Compile-time type checking and auto-generated client/server code in multiple languages", "Faster DNS resolution", "No need for versioning"], ans: 1, exp: "Protobuf-defined contracts allow code generation tools to produce strongly-typed client and server stubs across many languages, catching type mismatches at compile time." },
    { cat: "gRPC", q: "What gRPC streaming type would best fit a chat application with two-way real-time messaging?", opts: ["Unary", "Server streaming", "Client streaming", "Bidirectional streaming"], ans: 3, exp: "Bidirectional streaming allows both the client and server to send a sequence of messages independently over a single connection, ideal for chat-like applications." },
    { cat: "gRPC", q: "How does gRPC typically handle errors?", opts: ["HTTP status codes only", "Standardized status codes (e.g. OK, NOT_FOUND, UNAVAILABLE) returned in the response trailers along with an optional message", "Plain text error messages only", "gRPC does not support error reporting"], ans: 1, exp: "gRPC defines a standard set of status codes (like OK, CANCELLED, NOT_FOUND, UNAVAILABLE) returned in trailing metadata, along with optional human-readable error details." },
    { cat: "gRPC", q: "What is gRPC 'deadline/timeout' propagation used for?", opts: ["Compressing messages", "Allowing a client to specify how long it's willing to wait for an RPC to complete, propagated across service calls", "Encrypting traffic", "Load balancing"], ans: 1, exp: "Deadlines let a client specify a time limit for an RPC to complete; this can propagate through a chain of dependent calls so resources aren't wasted on requests that already timed out upstream." },
    { cat: "gRPC", q: "Which of the following is NOT a typical use case where gRPC shines?", opts: ["Microservice-to-microservice internal communication", "Low-latency, high-throughput streaming services", "Simple browser-based public APIs without any proxy", "Polyglot systems needing strongly typed contracts"], ans: 2, exp: "gRPC is excellent for internal service-to-service communication and streaming, but for simple public browser-facing APIs without a proxy, REST/JSON remains more broadly compatible." },

    // ── TCP ──
    { cat: "TCP", q: "What does TCP stand for?", opts: ["Transmission Control Protocol", "Transfer Control Protocol", "Total Control Protocol", "Transport Connection Protocol"], ans: 0, exp: "TCP stands for Transmission Control Protocol, a core protocol of the Internet protocol suite providing reliable, ordered, error-checked delivery of data." },
    { cat: "TCP", q: "Is TCP connection-oriented or connectionless?", opts: ["Connectionless", "Connection-oriented", "Both, depending on configuration", "Neither"], ans: 1, exp: "TCP is connection-oriented, meaning it establishes a dedicated end-to-end connection (via a handshake) before data transfer begins." },
    { cat: "TCP", q: "What is the TCP three-way handshake sequence?", opts: ["ACK, SYN, FIN", "SYN, SYN-ACK, ACK", "SYN, ACK, SYN", "FIN, ACK, SYN"], ans: 1, exp: "The TCP three-way handshake consists of SYN (client requests connection), SYN-ACK (server acknowledges and responds), and ACK (client confirms), establishing a reliable connection." },
    { cat: "TCP", q: "How does TCP guarantee reliable delivery of data?", opts: ["It doesn't guarantee reliability", "Through acknowledgments, sequence numbers, and retransmission of lost packets", "By using UDP underneath", "Through DNS caching"], ans: 1, exp: "TCP uses sequence numbers to order packets, acknowledgments to confirm receipt, and retransmits any packets that are lost or corrupted, ensuring reliable delivery." },
    { cat: "TCP", q: "What mechanism does TCP use to avoid overwhelming a slow receiver?", opts: ["DNS caching", "Flow control via a sliding window", "Packet fragmentation", "ARP resolution"], ans: 1, exp: "TCP flow control uses a sliding window mechanism where the receiver advertises how much data it can currently accept, preventing the sender from overwhelming it." },
    { cat: "TCP", q: "What is TCP 'congestion control' designed to do?", opts: ["Encrypt data in transit", "Prevent network congestion by adjusting the sending rate based on network conditions", "Resolve domain names", "Balance load across servers"], ans: 1, exp: "Congestion control algorithms (like TCP Reno, Cubic) dynamically adjust the sender's transmission rate to avoid overwhelming the network and causing packet loss." },
    { cat: "TCP", q: "How does a TCP connection get terminated gracefully?", opts: ["Immediately dropping all packets", "A four-way handshake involving FIN and ACK packets from both sides", "A single RST packet", "Through DNS expiry"], ans: 1, exp: "Graceful TCP termination typically uses a four-way handshake where each side sends a FIN and receives an ACK, ensuring both sides agree the connection is closing." },
    { cat: "TCP", q: "What does a TCP RST (reset) packet typically indicate?", opts: ["Normal connection closure", "An abrupt termination of the connection, often due to an error or unexpected state", "A retransmission request", "A keep-alive signal"], ans: 1, exp: "An RST packet abruptly terminates a connection, often sent when a host receives data for a connection it doesn't recognize or detects an unrecoverable error." },
    { cat: "TCP", q: "What is the purpose of TCP sequence numbers?", opts: ["To encrypt packets", "To allow the receiver to reorder out-of-order packets and detect missing data", "To identify the destination port", "To compress headers"], ans: 1, exp: "Sequence numbers let the receiving TCP stack reorder packets that arrive out of order and detect any missing segments that need retransmission." },
    { cat: "TCP", q: "What layer of the OSI model does TCP operate at?", opts: ["Layer 2 (Data Link)", "Layer 3 (Network)", "Layer 4 (Transport)", "Layer 7 (Application)"], ans: 2, exp: "TCP operates at Layer 4, the Transport layer, of the OSI model, providing reliable end-to-end communication between applications." },
    { cat: "TCP", q: "What is a TCP 'port'?", opts: ["A physical network connector", "A 16-bit number identifying a specific process/application endpoint on a host", "An IP address alias", "A routing table entry"], ans: 1, exp: "A TCP port is a 16-bit number (0-65535) that identifies a specific application or service endpoint on a host, allowing multiple network services to run on one IP address." },
    { cat: "TCP", q: "What does the term 'Nagle's algorithm' relate to in TCP?", opts: ["Encrypting TCP payloads", "Reducing the number of small packets sent by buffering and combining them", "Routing table optimization", "DNS caching"], ans: 1, exp: "Nagle's algorithm reduces network overhead by buffering small outgoing TCP segments and combining them into larger packets before sending, at the cost of added latency." },
    { cat: "TCP", q: "What is TCP 'keep-alive' used for?", opts: ["Encrypting idle connections", "Periodically probing an idle connection to verify the other end is still reachable", "Speeding up the handshake", "Compressing data"], ans: 1, exp: "TCP keep-alive sends periodic probe packets on an idle connection to detect if the remote end has become unreachable, preventing stale connections from lingering indefinitely." },
    { cat: "TCP", q: "What is 'head-of-line blocking' in the context of TCP?", opts: ["A DNS resolution delay", "A situation where a lost packet delays delivery of all subsequent packets in the stream until it's retransmitted", "A CPU bottleneck", "A firewall restriction"], ans: 1, exp: "Because TCP guarantees in-order delivery, if one packet is lost, all later packets must wait in the receive buffer until the lost packet is retransmitted and received — this is head-of-line blocking." },
    { cat: "TCP", q: "What does MSS stand for in TCP?", opts: ["Maximum Segment Size", "Minimum Send Size", "Multiple Stream Sessions", "Maximum System Speed"], ans: 0, exp: "MSS (Maximum Segment Size) specifies the largest amount of data, in bytes, that a TCP segment can carry, excluding TCP/IP headers." },
    { cat: "TCP", q: "In the TCP state machine, what state is a server socket in while waiting for incoming connections?", opts: ["ESTABLISHED", "LISTEN", "CLOSE_WAIT", "SYN_SENT"], ans: 1, exp: "A server socket enters the LISTEN state after calling listen(), waiting to accept incoming connection requests (SYN packets)." },
    { cat: "TCP", q: "What is a 'TCP window size'?", opts: ["The number of open connections allowed", "The amount of unacknowledged data that can be in transit, used for flow control", "The size of the IP header", "The maximum number of retransmissions"], ans: 1, exp: "The TCP window size indicates how much data the sender can transmit before requiring an acknowledgment, used to implement flow control between sender and receiver." },
    { cat: "TCP", q: "Which is a real-world example of an application protocol that runs over TCP?", opts: ["DNS (primarily)", "DHCP", "HTTP/1.1", "SNMP traps"], ans: 2, exp: "HTTP/1.1 runs over TCP to take advantage of its reliable, ordered delivery, which is important for transmitting web page content correctly." },
    { cat: "TCP", q: "What problem can occur due to TCP's reliability guarantees when used for real-time video/audio streaming?", opts: ["No problems at all", "Retransmission delays can cause noticeable lag, since TCP prioritizes order/completeness over timeliness", "TCP cannot transmit binary data", "TCP requires manual packet reordering by the app"], ans: 1, exp: "Because TCP insists on reordering and retransmitting lost packets before delivering data to the application, this can introduce latency that's undesirable for real-time media, which often prefers UDP instead." },
    { cat: "TCP", q: "What does 'TCP fast open' aim to reduce?", opts: ["DNS lookup time", "The round trip needed before sending data, by allowing data in the SYN packet", "Packet size", "Encryption overhead"], ans: 1, exp: "TCP Fast Open is an extension that allows data to be included in the initial SYN packet for previously-connected hosts, reducing one round trip of latency before data transfer." },

    // ── UDP ──
    { cat: "UDP", q: "What does UDP stand for?", opts: ["User Datagram Protocol", "Universal Data Protocol", "Unicast Delivery Protocol", "User Data Path"], ans: 0, exp: "UDP stands for User Datagram Protocol, a simple, connectionless transport layer protocol." },
    { cat: "UDP", q: "Is UDP connection-oriented or connectionless?", opts: ["Connection-oriented", "Connectionless", "It depends on the OS", "Hybrid"], ans: 1, exp: "UDP is connectionless — it sends datagrams without establishing a prior connection or handshake, unlike TCP." },
    { cat: "UDP", q: "Does UDP guarantee delivery of packets?", opts: ["Yes, always", "No, packets may be lost, duplicated, or arrive out of order with no guarantee", "Only on local networks", "Only with a special flag set"], ans: 1, exp: "UDP provides no guarantees of delivery, ordering, or duplicate protection — it's a best-effort protocol, trading reliability for speed and simplicity." },
    { cat: "UDP", q: "Why is UDP often preferred for real-time applications like video calls and gaming?", opts: ["It's more secure than TCP", "It has lower latency since it skips connection setup, acknowledgments, and retransmissions", "It uses less bandwidth always", "It's easier to encrypt"], ans: 1, exp: "UDP avoids the overhead of TCP's handshake, acknowledgment, and retransmission mechanisms, resulting in lower latency that's valuable for real-time applications where a few dropped packets are acceptable." },
    { cat: "UDP", q: "What is the size of a UDP header?", opts: ["8 bytes", "20 bytes", "12 bytes", "40 bytes"], ans: 0, exp: "The UDP header is a fixed 8 bytes, containing source port, destination port, length, and checksum — much simpler than TCP's variable-length header." },
    { cat: "UDP", q: "Which application protocol commonly uses UDP for fast, low-overhead lookups?", opts: ["HTTP", "DNS (typically for queries)", "FTP", "SMTP"], ans: 1, exp: "DNS commonly uses UDP for standard queries because of its low latency and minimal overhead, falling back to TCP for larger responses like zone transfers." },
    { cat: "UDP", q: "What does it mean that UDP is a 'best-effort' protocol?", opts: ["It tries to encrypt all data", "It delivers data without guarantees of reliability, ordering, or duplicate protection", "It guarantees at least one retry", "It only works on local networks"], ans: 1, exp: "Best-effort means UDP attempts to deliver datagrams but makes no guarantees about whether they arrive, arrive in order, or arrive only once." },
    { cat: "UDP", q: "Which of these protocols is built on top of UDP?", opts: ["FTP", "QUIC (used by HTTP/3)", "SSH", "Telnet"], ans: 1, exp: "QUIC, the transport protocol underlying HTTP/3, is built on top of UDP, adding its own reliability and congestion control while avoiding TCP's head-of-line blocking." },
    { cat: "UDP", q: "What happens to a UDP packet if it's lost in transit?", opts: ["It is automatically retransmitted by the protocol", "It is simply lost; the application must handle retransmission if needed", "UDP blocks until it's found", "The connection is terminated"], ans: 1, exp: "UDP has no built-in retransmission mechanism, so a lost packet is simply gone unless the application layer implements its own reliability logic." },
    { cat: "UDP", q: "Which use case is LEAST suited for UDP?", opts: ["Live video streaming", "Online multiplayer gaming", "File transfer requiring guaranteed byte-for-byte integrity", "DNS lookups"], ans: 2, exp: "File transfers requiring guaranteed, ordered, complete delivery are better suited to TCP, since UDP offers no reliability guarantees out of the box." },
    { cat: "UDP", q: "What is a 'UDP flood' attack?", opts: ["A legitimate high-traffic broadcast", "A denial-of-service attack that overwhelms a target with a large volume of UDP packets", "A DNS cache poisoning method", "A TCP handshake exploit"], ans: 1, exp: "A UDP flood is a DoS attack that sends a large volume of UDP packets to random ports on a target, consuming resources as the host responds with ICMP 'destination unreachable' messages." },
    { cat: "UDP", q: "Does UDP support multicast and broadcast communication?", opts: ["No, only TCP supports this", "Yes, UDP naturally supports one-to-many multicast and broadcast delivery", "Only broadcast, not multicast", "Only on IPv6"], ans: 1, exp: "UDP's connectionless nature makes it well-suited for multicast and broadcast communication, since it doesn't require a dedicated connection per recipient like TCP." },
    { cat: "UDP", q: "What transport protocol does RTP (Real-time Transport Protocol), used for VoIP/video, typically run over?", opts: ["TCP", "UDP", "ICMP", "SCTP only"], ans: 1, exp: "RTP typically runs over UDP to minimize latency for real-time audio/video, accepting the tradeoff of potential packet loss." },
    { cat: "UDP", q: "What field in the UDP header allows basic error detection?", opts: ["Sequence number", "Checksum", "Window size", "Acknowledgment number"], ans: 1, exp: "The UDP checksum field allows the receiver to detect corruption in the header and data, though UDP itself does not retransmit corrupted datagrams." },
    { cat: "UDP", q: "Why might a game developer choose UDP and build custom reliability on top of it rather than using raw TCP?", opts: ["UDP is always more secure", "To get fine-grained control over which data needs reliability/ordering and avoid TCP's head-of-line blocking for time-sensitive updates", "UDP automatically compresses data", "TCP cannot be used for games"], ans: 1, exp: "Game developers often build custom reliability layers on UDP so they can selectively retransmit only critical data while letting stale state updates (like outdated position data) simply be dropped, avoiding TCP's enforced in-order delivery delays." },

    // ── WEBSOCKETS ──
    { cat: "WebSockets", q: "What is the primary advantage of WebSockets over traditional HTTP polling?", opts: ["Better SEO", "A persistent, full-duplex connection enabling real-time, low-latency bidirectional communication", "Automatic encryption", "Smaller browser footprint"], ans: 1, exp: "WebSockets establish a single long-lived, full-duplex connection allowing both client and server to send messages at any time, avoiding the overhead and latency of repeated HTTP polling." },
    { cat: "WebSockets", q: "How does a WebSocket connection begin?", opts: ["As a UDP datagram", "As a regular HTTP request that is then 'upgraded' to the WebSocket protocol via a handshake", "As a raw TCP connection with no HTTP involved", "As a gRPC call"], ans: 1, exp: "A WebSocket connection starts as a standard HTTP request containing an 'Upgrade: websocket' header; if the server agrees, it responds with a 101 Switching Protocols status, upgrading the connection." },
    { cat: "WebSockets", q: "What HTTP status code is returned when a server accepts a WebSocket upgrade request?", opts: ["200 OK", "101 Switching Protocols", "301 Moved Permanently", "426 Upgrade Required"], ans: 1, exp: "A 101 Switching Protocols response indicates the server agrees to switch the connection from HTTP to the WebSocket protocol." },
    { cat: "WebSockets", q: "What URI scheme is used for secure WebSocket connections?", opts: ["http://", "https://", "ws://", "wss://"], ans: 3, exp: "wss:// denotes a WebSocket connection secured with TLS, analogous to https:// for HTTP, while ws:// is the unencrypted version." },
    { cat: "WebSockets", q: "Is WebSocket communication full-duplex or half-duplex?", opts: ["Half-duplex", "Full-duplex — both client and server can send messages independently at any time", "Simplex", "It depends on the browser"], ans: 1, exp: "WebSockets are full-duplex, meaning both the client and server can send data to each other simultaneously and independently over the same connection." },
    { cat: "WebSockets", q: "What header is sent by the client to initiate a WebSocket handshake?", opts: ["Connection: keep-alive only", "Upgrade: websocket", "Content-Type: websocket", "X-Websocket: true"], ans: 1, exp: "The client sends an 'Upgrade: websocket' header (along with 'Connection: Upgrade' and a Sec-WebSocket-Key) to request the protocol switch." },
    { cat: "WebSockets", q: "What is the purpose of the 'Sec-WebSocket-Key' header in the handshake?", opts: ["To encrypt the entire session", "To provide a value the server must transform and echo back, confirming it understands the WebSocket protocol and preventing caching proxy issues", "To authenticate the user", "To specify the subprotocol"], ans: 1, exp: "The Sec-WebSocket-Key is a randomly generated value the server must hash with a fixed GUID and return in Sec-WebSocket-Accept, confirming a genuine WebSocket-aware server handled the handshake." },
    { cat: "WebSockets", q: "At which OSI/transport layer does WebSocket ultimately operate after the handshake?", opts: ["It runs over UDP", "It runs over a single persistent TCP connection", "It replaces TCP entirely with a new protocol", "It runs over ICMP"], ans: 1, exp: "After the HTTP-based handshake, WebSocket frames are sent over the same underlying persistent TCP connection." },
    { cat: "WebSockets", q: "What is a common alternative to WebSockets for server-to-client one-way real-time updates?", opts: ["FTP", "Server-Sent Events (SSE)", "Telnet", "SOAP"], ans: 1, exp: "Server-Sent Events (SSE) provide a simpler, one-directional (server-to-client) persistent connection over plain HTTP, useful when bidirectional communication isn't needed." },
    { cat: "WebSockets", q: "What is a typical use case well-suited to WebSockets?", opts: ["Static file serving", "Live chat applications, collaborative editing, and real-time dashboards", "Batch file processing", "One-time form submissions"], ans: 1, exp: "WebSockets excel at use cases needing continuous, low-latency, bidirectional updates such as chat apps, multiplayer games, live dashboards, and collaborative document editing." },
    { cat: "WebSockets", q: "What does a WebSocket 'ping/pong' frame pair accomplish?", opts: ["Data compression", "Keeping the connection alive and verifying the remote endpoint is still responsive", "Authentication", "Encryption key exchange"], ans: 1, exp: "Ping and pong control frames let either endpoint verify the connection is still alive and responsive, similar to a heartbeat mechanism." },
    { cat: "WebSockets", q: "Can WebSocket connections pass through standard HTTP/HTTPS ports (80/443)?", opts: ["No, they require dedicated ports", "Yes, since they start as an HTTP handshake, they typically use ports 80 (ws) or 443 (wss)", "Only port 8080", "Only with a VPN"], ans: 1, exp: "Because the WebSocket handshake begins as a standard HTTP request, WebSocket connections commonly use the same ports as HTTP (80) and HTTPS (443), helping them pass through firewalls more easily." },
    { cat: "WebSockets", q: "What does the WebSocket 'close frame' (opcode) do?", opts: ["Pauses the connection temporarily", "Initiates a graceful closing handshake for the connection, optionally with a status code and reason", "Compresses remaining data", "Switches protocols again"], ans: 1, exp: "A close frame signals the intent to close the connection gracefully and can include a status code and human-readable reason explaining why." },
    { cat: "WebSockets", q: "What is a key scalability challenge with WebSocket servers?", opts: ["They cannot use load balancers at all", "Maintaining many long-lived open connections consumes server memory/resources differently than stateless HTTP request handling", "They cannot run on cloud infrastructure", "WebSockets cannot scale past 10 users"], ans: 1, exp: "Because WebSocket connections are long-lived and stateful, servers must manage and hold open many simultaneous connections, requiring different scaling strategies (like sticky sessions or pub/sub fan-out) than stateless HTTP." },
    { cat: "WebSockets", q: "What is the role of 'Socket.IO' relative to raw WebSockets?", opts: ["It's a replacement for TCP", "A library that builds on WebSockets (with fallbacks) and adds features like automatic reconnection, rooms, and event-based messaging", "A database driver", "A DNS resolver"], ans: 1, exp: "Socket.IO is a popular library that wraps WebSocket (falling back to other transports if needed) and adds conveniences like automatic reconnection, broadcasting, and rooms/namespaces." },

    // ── NETWORKING / GENERAL PROTOCOLS ──
    { cat: "Networking", q: "What does DNS stand for?", opts: ["Domain Name System", "Data Network Service", "Distributed Naming Standard", "Dynamic Network Setup"], ans: 0, exp: "DNS (Domain Name System) translates human-readable domain names like example.com into IP addresses that computers use to locate each other." },
    { cat: "Networking", q: "What is the default port for HTTP?", opts: ["443", "21", "80", "8080"], ans: 2, exp: "HTTP traditionally uses port 80 by default, while HTTPS uses port 443." },
    { cat: "Networking", q: "What is the default port for HTTPS?", opts: ["80", "443", "21", "22"], ans: 1, exp: "HTTPS, the encrypted version of HTTP using TLS/SSL, defaults to port 443." },
    { cat: "Networking", q: "What does TLS stand for?", opts: ["Transport Layer Security", "Total Link Security", "Transfer Level Service", "Trusted Local System"], ans: 0, exp: "TLS (Transport Layer Security) is a cryptographic protocol that provides secure communication over a network, succeeding the older SSL protocol." },
    { cat: "Networking", q: "What is the purpose of a load balancer?", opts: ["To encrypt traffic only", "To distribute incoming network traffic across multiple backend servers for reliability and performance", "To resolve domain names", "To compress HTTP responses"], ans: 1, exp: "A load balancer distributes incoming requests across multiple servers, improving availability, fault tolerance, and performance under load." },
    { cat: "Networking", q: "What does CDN stand for?", opts: ["Content Delivery Network", "Central Data Node", "Connected Distribution Node", "Client Data Network"], ans: 0, exp: "A CDN (Content Delivery Network) is a geographically distributed group of servers that cache and deliver content closer to end users, reducing latency." },
    { cat: "Networking", q: "How many layers does the OSI model have?", opts: ["5", "6", "7", "8"], ans: 2, exp: "The OSI (Open Systems Interconnection) model has seven layers: Physical, Data Link, Network, Transport, Session, Presentation, and Application." },
    { cat: "Networking", q: "Which OSI layer is responsible for routing packets between networks using IP addresses?", opts: ["Layer 2 (Data Link)", "Layer 3 (Network)", "Layer 4 (Transport)", "Layer 5 (Session)"], ans: 1, exp: "Layer 3, the Network layer, handles logical addressing (IP) and routing of packets across interconnected networks." },
    { cat: "Networking", q: "What protocol resolves an IP address to a MAC address on a local network?", opts: ["DNS", "ARP", "DHCP", "ICMP"], ans: 1, exp: "ARP (Address Resolution Protocol) maps an IP address to the corresponding hardware MAC address on a local area network." },
    { cat: "Networking", q: "What does DHCP stand for and do?", opts: ["Domain Host Connection Protocol — manages domains", "Dynamic Host Configuration Protocol — automatically assigns IP addresses and network configuration to devices", "Direct Host Control Protocol — load balances traffic", "Data Handling Control Protocol — encrypts packets"], ans: 1, exp: "DHCP (Dynamic Host Configuration Protocol) automatically assigns IP addresses and other network configuration parameters to devices joining a network." },
    { cat: "Networking", q: "What is the main improvement HTTP/2 introduced over HTTP/1.1?", opts: ["Plain text headers", "Multiplexing multiple requests over a single TCP connection, reducing head-of-line blocking at the HTTP layer", "Removing TLS support", "Switching to UDP"], ans: 1, exp: "HTTP/2 introduced multiplexing, allowing multiple requests and responses to be interleaved over a single TCP connection, along with header compression, reducing latency compared to HTTP/1.1." },
    { cat: "Networking", q: "What transport protocol does HTTP/3 use?", opts: ["TCP", "UDP (via QUIC)", "SCTP", "ICMP"], ans: 1, exp: "HTTP/3 is built on QUIC, which runs over UDP, eliminating TCP's head-of-line blocking and improving connection setup speed." },
    { cat: "Networking", q: "What is the purpose of a firewall?", opts: ["To speed up DNS lookups", "To monitor and control incoming/outgoing network traffic based on security rules", "To cache static content", "To balance load between servers"], ans: 1, exp: "A firewall is a network security device/software that monitors and filters incoming and outgoing traffic based on predefined security rules." },
    { cat: "Networking", q: "What does NAT stand for?", opts: ["Network Address Translation", "Node Authentication Token", "Network Access Tunnel", "Native Address Type"], ans: 0, exp: "NAT (Network Address Translation) allows multiple devices on a private network to share a single public IP address by translating addresses at the router." },
    { cat: "Networking", q: "What is the purpose of a reverse proxy?", opts: ["To hide a client's identity from the internet", "To sit in front of backend servers, forwarding client requests to them and returning responses, often providing load balancing/caching/SSL termination", "To resolve DNS queries only", "To act as a database replica"], ans: 1, exp: "A reverse proxy sits between clients and backend servers, forwarding requests to the appropriate server while providing features like load balancing, caching, SSL termination, and security." },
    { cat: "Networking", q: "What does MTU stand for in networking?", opts: ["Maximum Transmission Unit", "Minimum Transfer Unit", "Multiple Transport Uplink", "Managed Traffic Utility"], ans: 0, exp: "MTU (Maximum Transmission Unit) defines the largest size, in bytes, of a packet that can be transmitted over a network link without fragmentation." },
    { cat: "Networking", q: "What is the purpose of an API Gateway in a microservices architecture?", opts: ["To store data permanently", "To act as a single entry point that routes, authenticates, and aggregates requests to backend microservices", "To compile source code", "To manage DNS records only"], ans: 1, exp: "An API Gateway provides a unified entry point for clients, handling cross-cutting concerns like routing, authentication, rate limiting, and aggregation across multiple backend microservices." },
    { cat: "Networking", q: "What is the main difference between IPv4 and IPv6 addresses?", opts: ["IPv6 uses 32-bit addresses, IPv4 uses 128-bit", "IPv4 uses 32-bit addresses (about 4.3 billion), IPv6 uses 128-bit addresses, vastly expanding the address space", "They are functionally identical", "IPv6 cannot be routed on the internet"], ans: 1, exp: "IPv4 addresses are 32 bits, providing roughly 4.3 billion unique addresses, while IPv6 uses 128-bit addresses, providing a vastly larger address space to accommodate internet growth." },
    { cat: "Networking", q: "What is the function of the TLS handshake?", opts: ["To compress packets", "To negotiate encryption parameters and authenticate the server (and optionally client) before establishing a secure encrypted channel", "To resolve hostnames", "To balance load"], ans: 1, exp: "The TLS handshake negotiates the cryptographic algorithms, exchanges keys, and verifies certificates to establish a secure, encrypted communication channel between client and server." },
    { cat: "Networking", q: "What is a 'man-in-the-middle' attack?", opts: ["A type of DDoS attack", "An attack where an adversary secretly intercepts and possibly alters communication between two parties who believe they're directly communicating", "A SQL injection technique", "A type of phishing email only"], ans: 1, exp: "A man-in-the-middle attack occurs when an attacker secretly intercepts (and possibly modifies) communications between two parties who believe they are talking directly to each other." },
    { cat: "Networking", q: "What does 'idempotent' mean when applied broadly to network operations?", opts: ["The operation always fails the second time", "Performing the operation multiple times has the same effect as performing it once", "The operation is always asynchronous", "The operation requires authentication"], ans: 1, exp: "An idempotent operation produces the same result regardless of how many times it's performed, which is valuable for safely retrying network requests after timeouts or failures." },
    { cat: "Networking", q: "What is the purpose of rate limiting in API design?", opts: ["To encrypt requests", "To restrict the number of requests a client can make in a given time window, protecting the service from abuse or overload", "To compress responses", "To cache static assets"], ans: 1, exp: "Rate limiting caps how many requests a client can send within a time period, protecting backend services from being overwhelmed and ensuring fair resource usage." },
    { cat: "Networking", q: "What is a 'webhook'?", opts: ["A type of firewall rule", "An HTTP callback where a server sends real-time data to a client-provided URL when an event occurs", "A WebSocket library", "A DNS record type"], ans: 1, exp: "A webhook is a mechanism where a server makes an HTTP request (usually POST) to a client-specified URL automatically when a particular event occurs, enabling event-driven integrations." },
    { cat: "Networking", q: "What is the difference between authentication and authorization?", opts: ["They are the same thing", "Authentication verifies who you are; authorization determines what you're allowed to do", "Authentication is for servers only; authorization is for clients only", "Authorization always happens before authentication"], ans: 1, exp: "Authentication verifies a user's or system's identity, while authorization determines what actions or resources that authenticated identity is permitted to access." },
    { cat: "Networking", q: "What is JWT commonly used for in API security?", opts: ["Encrypting database rows", "A compact, self-contained token format used to securely transmit claims (like user identity) between parties for authentication/authorization", "Compressing JSON payloads", "Routing HTTP requests"], ans: 1, exp: "JWT (JSON Web Token) is a compact, signed token format commonly used to convey authentication claims between parties, allowing stateless verification of a user's identity on each request." },
    { cat: "Networking", q: "What does mTLS (mutual TLS) provide beyond standard TLS?", opts: ["Faster encryption only", "Both the client and server authenticate each other using certificates, not just the server authenticating to the client", "Only used for DNS", "Removes the need for certificates entirely"], ans: 1, exp: "In mutual TLS, both client and server present and verify certificates, providing two-way authentication rather than just the server proving its identity to the client." },
    { cat: "Networking", q: "What is 'service discovery' in a microservices architecture?", opts: ["A static configuration file only", "The mechanism by which services dynamically locate the network addresses of other services they need to call", "A type of firewall", "A database backup strategy"], ans: 1, exp: "Service discovery allows services in a dynamic environment (like containers/cloud) to find each other's current network locations automatically, rather than relying on hardcoded addresses." },
    { cat: "Networking", q: "What is the purpose of a circuit breaker pattern in distributed systems?", opts: ["To physically disconnect network cables", "To stop sending requests to a failing service temporarily, preventing cascading failures and allowing it time to recover", "To encrypt traffic between services", "To compress API responses"], ans: 1, exp: "The circuit breaker pattern detects repeated failures calling a dependent service and 'trips', temporarily blocking further calls to prevent cascading failures and give the failing service time to recover." },
    { cat: "Networking", q: "What does 'eventual consistency' mean in distributed systems?", opts: ["Data is always immediately consistent across all nodes", "Given enough time without new updates, all replicas of data will converge to the same value, though they may be temporarily inconsistent", "Data consistency is never guaranteed", "It refers only to caching"], ans: 1, exp: "Eventual consistency means that if no new updates occur, all distributed replicas of a piece of data will eventually converge to the same value, though there may be a temporary window of inconsistency." },
    { cat: "Networking", q: "What is 'Server-Sent Events' (SSE) best suited for?", opts: ["Bidirectional binary file transfer", "One-way streaming of text-based updates from server to client over a single long-lived HTTP connection", "Peer-to-peer file sharing", "UDP-based gaming"], ans: 1, exp: "SSE provides a simple way for servers to push a stream of text-based event updates to clients over a standard, long-lived HTTP connection, well-suited for things like live notifications or feeds." },
    { cat: "Networking", q: "What does 'long polling' refer to?", opts: ["A WebSocket variant", "A technique where the client makes a request that the server holds open until new data is available, then responds, and the client immediately re-requests", "A type of DNS query", "A TCP retransmission strategy"], ans: 1, exp: "Long polling simulates real-time updates over plain HTTP by having the server delay its response until new data is ready, after which the client immediately issues a new request to continue 'listening'." },
    { cat: "Networking", q: "What is the purpose of HTTP 'Keep-Alive'?", opts: ["To encrypt the connection", "To allow a single TCP connection to be reused for multiple HTTP requests/responses instead of opening a new connection each time", "To compress headers", "To cache DNS records"], ans: 1, exp: "HTTP Keep-Alive allows the underlying TCP connection to remain open and be reused for subsequent requests, avoiding the overhead of repeated connection setup/teardown." },
    { cat: "Networking", q: "What is the role of an SSL/TLS certificate?", opts: ["To compress data faster", "To cryptographically bind a public key to an identity (like a domain), allowing clients to verify the server's authenticity", "To balance network load", "To resolve domain names"], ans: 1, exp: "An SSL/TLS certificate, issued by a trusted Certificate Authority, binds a public key to an identity such as a domain name, enabling clients to verify they're communicating with the legitimate server." },
    { cat: "Networking", q: "What does 'sharding' mean in the context of distributed databases/networking?", opts: ["Encrypting data at rest", "Splitting a large dataset across multiple servers/partitions to distribute load and storage", "Compressing network packets", "Caching responses at the edge"], ans: 1, exp: "Sharding partitions a large dataset across multiple database instances or nodes, distributing storage and query load to improve scalability." },
    { cat: "Networking", q: "What is the difference between unicast, multicast, and broadcast communication?", opts: ["They are all identical terms for the same concept", "Unicast is one-to-one, multicast is one-to-many (to a specific group), and broadcast is one-to-all on a network", "Unicast is encrypted, multicast and broadcast are not", "Broadcast only works over UDP, unicast only over TCP"], ans: 1, exp: "Unicast sends data from one sender to one specific receiver, multicast sends to a specific group of interested receivers, and broadcast sends to all devices on a network segment." },
    { cat: "Networking", q: "What is the purpose of an SLA in API/service contexts?", opts: ["A type of database index", "A Service Level Agreement defining expected performance/availability guarantees between a provider and consumer", "A security protocol", "A caching mechanism"], ans: 1, exp: "An SLA (Service Level Agreement) formally defines the expected level of service — such as uptime, response time, or throughput — that a provider commits to delivering." },
    { cat: "Networking", q: "What does 'idempotency' have to do with retry logic in distributed systems?", opts: ["It prevents retries from ever happening", "It allows clients to safely retry failed requests without worrying about causing duplicate side effects", "It is unrelated to retries", "It only applies to read operations"], ans: 1, exp: "Designing operations to be idempotent means that retrying a request after a timeout or failure (without knowing if it originally succeeded) won't cause unintended duplicate effects, like double-charging a payment." },
    { cat: "Networking", q: "What is 'backpressure' in the context of streaming systems/networking?", opts: ["A type of network attack", "A mechanism by which a slow consumer signals a fast producer to slow down, preventing buffer overflow or resource exhaustion", "An encryption algorithm", "A DNS caching technique"], ans: 1, exp: "Backpressure refers to mechanisms that allow a consumer that can't keep up with incoming data to signal the producer to slow down, preventing memory exhaustion or dropped data." },
    { cat: "Networking", q: "What is the purpose of the OSI Session layer (Layer 5)?", opts: ["Physical cabling", "Establishing, managing, and terminating sessions/connections between applications", "Routing packets", "Encrypting data only"], ans: 1, exp: "The Session layer manages and controls the dialogue (sessions) between two communicating applications, including establishing, synchronizing, and terminating the session." },
    { cat: "Networking", q: "What is the role of the OSI Presentation layer (Layer 6)?", opts: ["Physical transmission of bits", "Translating, encrypting, and compressing data so it's in a usable format for the Application layer", "Routing between networks", "Establishing TCP connections"], ans: 1, exp: "The Presentation layer handles data translation, encryption/decryption, and compression, ensuring data is presented in a format the Application layer can use." },
    { cat: "Networking", q: "What does 'polyglot persistence' refer to in modern distributed architectures?", opts: ["Supporting many spoken languages in UI", "Using different types of databases/storage technologies best suited to different parts of an application", "A type of network protocol", "A caching algorithm"], ans: 1, exp: "Polyglot persistence is the practice of using multiple different data storage technologies (SQL, NoSQL, cache, etc.) within a single application, each chosen for the specific needs of a given component." },
    { cat: "Networking", q: "In API design, what is the difference between synchronous and asynchronous communication?", opts: ["They are the same", "Synchronous communication blocks the caller until a response is received; asynchronous lets the caller continue without waiting, often via callbacks/events/queues", "Asynchronous only works with REST", "Synchronous only works with gRPC"], ans: 1, exp: "Synchronous communication requires the caller to wait for an immediate response before proceeding, while asynchronous communication lets the caller continue other work and receive a result later, often through callbacks, events, or message queues." },
    { cat: "Networking", q: "What is the purpose of message queues (e.g. RabbitMQ, Kafka) in networked systems?", opts: ["To encrypt network traffic", "To decouple producers and consumers, buffering and reliably delivering messages asynchronously between services", "To resolve DNS names", "To replace TCP entirely"], ans: 1, exp: "Message queues decouple the components that produce data from those that consume it, providing buffering, reliable delivery, and asynchronous processing between distributed services." },
    { cat: "Networking", q: "What is 'protocol buffer' (protobuf) primarily designed to optimize for, compared to JSON?", opts: ["Human readability", "Compact binary size and fast serialization/deserialization performance", "Browser compatibility", "SQL query speed"], ans: 1, exp: "Protocol Buffers are a binary serialization format designed for compactness and speed, trading human readability (which JSON has) for smaller payloads and faster parsing." },
    { cat: "Networking", q: "What is the purpose of a 'sticky session' in load balancing?", opts: ["To encrypt all sessions", "To consistently route a given client's requests to the same backend server, often needed for stateful applications", "To compress responses", "To resolve DNS faster"], ans: 1, exp: "Sticky sessions (session affinity) ensure that requests from the same client are consistently routed to the same backend server, which can be necessary when server-side session state isn't shared across instances." },
    { cat: "Networking", q: "What does 'API throttling' typically protect against?", opts: ["SQL injection", "Resource exhaustion and abuse caused by clients sending excessive requests in a short time", "Cross-site scripting", "DNS spoofing"], ans: 1, exp: "API throttling limits the rate at which a client can call an API, protecting backend resources from being overwhelmed by excessive or abusive traffic." },
    { cat: "Networking", q: "What is the key tradeoff between strong consistency and high availability described by the CAP theorem?", opts: ["There is no tradeoff; you can have all three of consistency, availability, and partition tolerance simultaneously", "In the presence of a network partition, a distributed system must choose between consistency and availability", "CAP theorem only applies to single-node systems", "CAP theorem is about encryption strength"], ans: 1, exp: "The CAP theorem states that a distributed system can only provide two of three guarantees — Consistency, Availability, and Partition tolerance — simultaneously; since partitions are unavoidable in practice, systems must choose between consistency and availability during a partition." },
    { cat: "Networking", q: "What is the purpose of exponential backoff in retry strategies?", opts: ["To retry as fast as possible every time", "To progressively increase the wait time between retries after failures, reducing load on a struggling service and avoiding thundering herd problems", "To encrypt retried requests", "To switch protocols on each retry"], ans: 1, exp: "Exponential backoff increases the delay between successive retry attempts exponentially, preventing clients from hammering an already-struggling service and reducing the risk of synchronized retry storms (thundering herd)." },

    // ── ADDITIONAL: REST ──
    { cat: "REST", q: "What HTTP status code indicates 'Method Not Allowed'?", opts: ["404", "405", "406", "415"], ans: 1, exp: "405 Method Not Allowed indicates the HTTP method used is not supported for the requested resource, even though the resource itself exists." },
    { cat: "REST", q: "What is the purpose of the 'Allow' response header?", opts: ["To list permitted CORS origins", "To list the HTTP methods supported by a resource, often sent with a 405 response", "To specify allowed IP addresses", "To enable caching"], ans: 1, exp: "The Allow header lists the HTTP methods that a resource supports, commonly returned alongside a 405 Method Not Allowed response." },
    { cat: "REST", q: "What does 'REST is layered system' constraint mean?", opts: ["The API must use exactly 3 servers", "A client cannot ordinarily tell whether it's connected directly to the end server or to an intermediary like a proxy or load balancer", "All requests must pass through 7 layers of the OSI model", "Resources must be nested in URLs"], ans: 1, exp: "The layered system constraint means intermediary servers (proxies, gateways, load balancers) can be introduced between client and server without the client needing to know, as long as the interface contract is preserved." },

    // ── ADDITIONAL: GraphQL ──
    { cat: "GraphQL", q: "What does the GraphQL 'enum' type represent?", opts: ["A free-form string", "A special scalar restricted to a defined set of allowed values", "A binary file type", "A nested object only"], ans: 1, exp: "An enum type defines a field that can only take on one of a specific, predefined set of values, improving validation and clarity." },
    { cat: "GraphQL", q: "What is the purpose of the '!' (non-null) symbol in a GraphQL schema, e.g. String!?", opts: ["It marks the field as deprecated", "It indicates the field can never return null and must always have a value", "It marks the field as a list", "It indicates the field is read-only"], ans: 1, exp: "Appending ! to a type marks it as non-nullable, meaning the server guarantees that field will always return a value (never null) or the query will error." },
    { cat: "GraphQL", q: "How would you denote a list of non-null strings that can itself be null in GraphQL SDL?", opts: ["[String!]", "String[]!", "[String]!", "!String[]"], ans: 0, exp: "[String!] denotes a nullable list containing non-null String elements — the list itself may be null, but if present, none of its items can be null." },

    // ── ADDITIONAL: gRPC ──
    { cat: "gRPC", q: "What is 'gRPC-Web' designed to enable?", opts: ["Running gRPC directly in browsers via a compatible JavaScript client and proxy, since browsers can't fully support raw gRPC over HTTP/2", "Hosting gRPC servers on a CDN", "Encrypting protobuf at rest", "Replacing JSON entirely in REST APIs"], ans: 0, exp: "gRPC-Web is a JavaScript implementation that lets browser-based clients call gRPC services, typically routed through a proxy (like Envoy) that translates between gRPC-Web and native gRPC." },
    { cat: "gRPC", q: "What does 'server streaming RPC' mean in gRPC?", opts: ["The client sends a stream of messages and gets one response", "The client sends one request and receives a stream of multiple responses from the server", "Both sides stream simultaneously", "Streaming is not supported"], ans: 1, exp: "In server streaming RPC, the client sends a single request and the server responds with a sequence (stream) of messages, useful for cases like delivering large result sets incrementally." },

    // ── ADDITIONAL: TCP ──
    { cat: "TCP", q: "What does the acronym 'ACK' refer to in TCP?", opts: ["A Connection Key", "Acknowledgment — a flag/segment confirming receipt of data", "Active Connection Kill", "Application Connection Kernel"], ans: 1, exp: "ACK (acknowledgment) is a TCP flag/segment used to confirm that data has been successfully received, central to TCP's reliability guarantees." },
    { cat: "TCP", q: "What is 'TCP slow start' designed to do?", opts: ["Delay the handshake intentionally", "Gradually increase the sending rate at the start of a connection to avoid immediately overwhelming the network", "Slow down DNS resolution", "Reduce encryption overhead"], ans: 1, exp: "TCP slow start begins a new connection with a small congestion window and increases it gradually as acknowledgments are received, avoiding an abrupt burst of traffic that could cause congestion." },

    // ── ADDITIONAL: UDP ──
    { cat: "UDP", q: "Which is true about UDP's overhead compared to TCP?", opts: ["UDP has higher overhead due to encryption", "UDP has lower overhead since it skips connection setup, acknowledgments, and retransmission logic", "UDP and TCP have identical overhead", "UDP requires more header bytes than TCP"], ans: 1, exp: "UDP has significantly lower overhead than TCP because it has a simpler 8-byte header and skips connection establishment, acknowledgments, and retransmission machinery." },
    { cat: "UDP", q: "What does TFTP (Trivial File Transfer Protocol) use as its transport?", opts: ["TCP", "UDP", "SCTP", "ICMP"], ans: 1, exp: "TFTP is a simplified file transfer protocol that runs over UDP, commonly used for tasks like network booting where simplicity and low overhead matter more than reliability guarantees." },

    // ── ADDITIONAL: WebSockets ──
    { cat: "WebSockets", q: "What WebSocket frame type is used to send text data?", opts: ["Binary frame", "Text frame", "Ping frame", "Close frame"], ans: 1, exp: "WebSocket text frames carry UTF-8 encoded text data, while binary frames carry arbitrary binary data; both are distinct opcode types in the protocol." },
    { cat: "WebSockets", q: "Why might a WebSocket connection fail behind certain corporate proxies?", opts: ["WebSockets never work behind any proxy", "Some older or restrictive proxies don't support the HTTP Upgrade mechanism needed to establish a WebSocket connection", "WebSockets require IPv6", "WebSockets are blocked by all firewalls by design"], ans: 1, exp: "Some proxies and middleboxes don't properly support the HTTP Upgrade header mechanism required to switch a connection to the WebSocket protocol, which can cause connection failures." },

    // ── ADDITIONAL: Networking ──
    { cat: "Networking", q: "What is the purpose of the HTTP 'Authorization' header?", opts: ["To specify content language", "To carry credentials (e.g. Bearer token, Basic auth) for authenticating a request", "To specify cache duration", "To redirect requests"], ans: 1, exp: "The Authorization header carries credentials such as a Bearer token or Basic auth string, used by the server to authenticate the request." },
    { cat: "Networking", q: "What does 'idempotent retries with a dead letter queue' help achieve in messaging systems?", opts: ["Faster encryption", "Capturing messages that repeatedly fail processing so they can be inspected/handled separately instead of blocking the queue indefinitely", "Reducing message size", "Eliminating the need for acknowledgments"], ans: 1, exp: "A dead letter queue captures messages that fail processing after repeated retries, preventing them from blocking the main queue while preserving them for investigation or manual handling." },
    { cat: "Networking", q: "What is the function of an 'Ingress controller' in a Kubernetes networking context?", opts: ["To manage container images", "To manage external access (typically HTTP/HTTPS) to services running inside a cluster, often providing routing, TLS termination, and load balancing", "To handle DNS for the cluster only", "To compile application code"], ans: 1, exp: "An Ingress controller implements rules for routing external HTTP/HTTPS traffic to the appropriate internal Kubernetes services, often also handling TLS termination and load balancing." },
    { cat: "Networking", q: "What does 'zero trust networking' assume by default?", opts: ["All internal traffic is automatically trusted", "No user or device should be trusted by default, even inside the network perimeter, and every request must be verified", "Encryption is unnecessary if behind a firewall", "Only external traffic needs authentication"], ans: 1, exp: "Zero trust networking operates on the principle that no request — internal or external — should be implicitly trusted; every access attempt must be authenticated and authorized." },
    { cat: "Networking", q: "What is the role of a 'health check' endpoint in a microservice?", opts: ["To run automated tests", "To allow load balancers/orchestrators to verify the service instance is running and ready to accept traffic", "To encrypt service-to-service calls", "To log all requests"], ans: 1, exp: "A health check endpoint allows infrastructure components like load balancers or container orchestrators to periodically verify that a service instance is alive and ready to handle traffic, removing unhealthy instances from rotation." },
    { cat: "Networking", q: "What is 'gRPC reflection' used for?", opts: ["Encrypting messages twice", "Allowing clients (like debugging tools) to query a running gRPC server at runtime to discover its services and message types without needing the original .proto file", "Mirroring traffic to a backup server", "Load balancing requests"], ans: 1, exp: "Server reflection lets tools like grpcurl or Postman query a running gRPC server to discover available services and message definitions dynamically, without requiring access to the original .proto files." },
    { cat: "Networking", q: "What does 'connection pooling' achieve in client-server communication?", opts: ["Encrypting all pooled connections automatically", "Reusing a set of established connections across multiple requests instead of opening and closing a new connection each time, reducing overhead", "Load balancing DNS queries", "Compressing request bodies"], ans: 1, exp: "Connection pooling maintains a reusable set of open connections (e.g. TCP/database connections) that can be borrowed and returned across requests, avoiding the repeated cost of establishing new connections." },
    { cat: "Networking", q: "What is the difference between a forward proxy and a reverse proxy?", opts: ["They are identical concepts", "A forward proxy sits in front of clients and forwards their requests outward to the internet; a reverse proxy sits in front of servers and forwards client requests inward to them", "A forward proxy only works with UDP; reverse proxy only with TCP", "Forward proxies are illegal; reverse proxies are not"], ans: 1, exp: "A forward proxy acts on behalf of clients, routing their outbound requests (often for anonymity or filtering), while a reverse proxy acts on behalf of servers, routing inbound client requests to the appropriate backend." },

    // ── MORE NETWORKING ──
    { cat: "Networking", q: "What is 'split-horizon DNS'?", opts: ["A DNS backup strategy", "A configuration where DNS returns different results depending on whether the query originates from inside or outside a network", "A type of DNS attack", "A method of encrypting DNS queries"], ans: 1, exp: "Split-horizon (or split-view) DNS serves different answers for the same domain name depending on the source of the query, commonly used to give internal clients private IPs and external clients public IPs." },
    { cat: "Networking", q: "What does 'anycast' routing allow?", opts: ["Sending data to a single fixed destination only", "Multiple servers in different locations sharing the same IP address, with traffic routed to the nearest/best instance", "Encrypting traffic between two specific hosts", "Broadcasting to every host on a LAN"], ans: 1, exp: "Anycast allows multiple geographically distributed servers to advertise the same IP address, with network routing sending each client to the topologically nearest instance, commonly used by DNS root servers and CDNs." },
    { cat: "Networking", q: "What is the purpose of BGP (Border Gateway Protocol)?", opts: ["Resolving hostnames to IPs", "Exchanging routing information between autonomous systems to determine the best paths across the internet", "Encrypting application data", "Assigning local IP addresses to devices"], ans: 1, exp: "BGP is the protocol that exchanges routing and reachability information between autonomous systems, effectively forming the routing backbone of the internet." },
    { cat: "Networking", q: "What is a 'subnet mask' used for?", opts: ["Encrypting IP packets", "Dividing an IP address into network and host portions to define the boundaries of a subnetwork", "Compressing IP headers", "Resolving MAC addresses"], ans: 1, exp: "A subnet mask determines which portion of an IP address identifies the network and which portion identifies the host, defining the boundaries of a subnet." },
    { cat: "Networking", q: "What does CIDR notation (e.g. 192.168.1.0/24) represent?", opts: ["A MAC address format", "A compact way to denote an IP address range along with the number of bits used for the network prefix", "An encryption key length", "A DNS record type"], ans: 1, exp: "CIDR (Classless Inter-Domain Routing) notation specifies an IP address along with a slash and a number indicating how many leading bits form the network portion, defining the address range/subnet size." },
    { cat: "Networking", q: "What is the purpose of an 'edge function' or 'edge computing' in a CDN context?", opts: ["Storing the entire database at the edge", "Running lightweight compute logic at geographically distributed edge locations close to users, reducing latency for dynamic logic", "Encrypting traffic only at the origin", "Replacing DNS with static routing"], ans: 1, exp: "Edge computing/functions let small pieces of application logic run at CDN edge locations near the user, reducing latency for tasks like request routing, personalization, or authentication checks compared to round-tripping to a central origin server." },
    { cat: "Networking", q: "What does 'TTL' (Time To Live) control in a DNS record?", opts: ["How long a TCP connection stays open", "How long a resolver/cache is allowed to cache a DNS record before re-querying the authoritative server", "The lifespan of an HTTP session", "The expiration of an SSL certificate"], ans: 1, exp: "TTL on a DNS record specifies, in seconds, how long resolvers should cache that record before querying the authoritative nameserver again for a fresh value." },
    { cat: "Networking", q: "What is 'DNSSEC' designed to protect against?", opts: ["Slow DNS lookups", "DNS spoofing/cache poisoning attacks, by cryptographically signing DNS records to verify authenticity", "High DNS query volume", "Expired domain registrations"], ans: 1, exp: "DNSSEC (Domain Name System Security Extensions) adds cryptographic signatures to DNS records, allowing resolvers to verify that responses haven't been tampered with or forged." },
    { cat: "Networking", q: "What is a 'race condition' in the context of concurrent network requests?", opts: ["A type of DDoS attack", "A bug where the outcome depends unpredictably on the relative timing of concurrent operations, such as two requests modifying shared state simultaneously", "A DNS resolution delay", "A TCP retransmission timeout"], ans: 1, exp: "A race condition occurs when the behavior of a system depends on the uncontrolled timing or interleaving of concurrent operations, which can lead to inconsistent or incorrect results, especially with shared/contended resources." },
    { cat: "Networking", q: "What is the purpose of 'blue-green deployment' from a networking/traffic perspective?", opts: ["Encrypting two environments differently", "Running two identical production environments and switching traffic (often via a load balancer/router) from the old to the new version for zero-downtime releases", "Splitting traffic randomly between every available server version", "A type of database replication"], ans: 1, exp: "Blue-green deployment maintains two identical environments; traffic is routed to one (e.g. blue) while the other (green) is updated and tested, then traffic is switched over, enabling near-instant rollback if issues arise." },
    { cat: "Networking", q: "What does 'canary deployment' refer to?", opts: ["Deploying to a single user only", "Gradually rolling out a new version to a small subset of traffic/users before a full rollout, to catch issues early", "Deploying without any testing", "A type of database backup"], ans: 1, exp: "Canary deployment routes a small percentage of traffic to a new version first, monitoring for errors before gradually increasing the traffic share, limiting the blast radius of potential issues." },
    { cat: "Networking", q: "What is 'mTLS' commonly used for in a service mesh like Istio?", opts: ["Compressing service payloads", "Automatically encrypting and mutually authenticating traffic between services within the mesh", "Load balancing DNS queries", "Replacing Kubernetes entirely"], ans: 1, exp: "Service meshes commonly use mutual TLS to automatically encrypt and authenticate service-to-service traffic within the mesh, without requiring each application to implement TLS itself." },
    { cat: "Networking", q: "What is the role of a 'sidecar proxy' in a service mesh architecture?", opts: ["Storing application logs only", "Running alongside each service instance to intercept and manage network traffic (routing, retries, mTLS, observability) transparently", "Compiling application code", "Resolving DNS for the entire cluster"], ans: 1, exp: "A sidecar proxy (like Envoy in Istio) runs as a companion process alongside each service instance, transparently handling networking concerns such as routing, retries, load balancing, and mTLS without changing application code." },
    { cat: "Networking", q: "What is 'Cross-Origin Resource Sharing' (CORS) designed to control?", opts: ["Encryption of cross-origin traffic", "Whether a web page from one origin is allowed to make requests to a server on a different origin", "DNS resolution across domains", "Load balancing between origins"], ans: 1, exp: "CORS is a browser security mechanism that uses HTTP headers to let a server specify which other origins are permitted to make cross-origin requests to it, protecting against unauthorized cross-site access." },

    // ── AWS NETWORKING ──
    { cat: "AWS Networking", q: "What does VPC stand for in AWS?", opts: ["Virtual Private Cloud", "Virtual Public Connection", "Verified Private Compute", "Virtual Protocol Container"], ans: 0, exp: "A VPC (Virtual Private Cloud) is a logically isolated virtual network within AWS where you can launch resources and control networking configuration like IP ranges, subnets, and routing." },
    { cat: "AWS Networking", q: "What is the purpose of subnets within an AWS VPC?", opts: ["To encrypt traffic between regions", "To divide a VPC's IP address range into smaller segments, often used to separate public-facing and private resources across availability zones", "To create a new AWS account", "To define IAM permissions"], ans: 1, exp: "Subnets divide a VPC's CIDR block into smaller ranges, typically associated with specific availability zones, allowing resources to be organized as public (internet-facing) or private (internal only)." },
    { cat: "AWS Networking", q: "What is the difference between a public subnet and a private subnet in AWS?", opts: ["Public subnets are free; private subnets cost money", "A public subnet has a route to an Internet Gateway, allowing direct internet access; a private subnet does not have such a direct route", "Private subnets cannot contain EC2 instances", "Public subnets only support IPv6"], ans: 1, exp: "A subnet is considered 'public' if its route table includes a route to an Internet Gateway; a 'private' subnet lacks this direct route, typically reaching the internet (if needed) only via a NAT Gateway." },
    { cat: "AWS Networking", q: "What is the function of an Internet Gateway (IGW) in AWS?", opts: ["To encrypt VPC traffic", "To allow resources in a VPC to communicate with the public internet", "To connect two VPCs together privately", "To resolve DNS within the VPC"], ans: 1, exp: "An Internet Gateway is a horizontally scaled, redundant VPC component that allows communication between instances in a VPC and the public internet." },
    { cat: "AWS Networking", q: "What is the purpose of a NAT Gateway in AWS?", opts: ["To allow inbound internet traffic to private subnet resources", "To allow instances in a private subnet to initiate outbound internet connections while preventing unsolicited inbound connections from the internet", "To balance load between EC2 instances", "To act as a VPN endpoint"], ans: 1, exp: "A NAT Gateway lets instances in a private subnet access the internet (e.g. for updates) by translating their private IPs to a public IP for outbound traffic, while blocking unsolicited inbound connections initiated from outside." },
    { cat: "AWS Networking", q: "What is the key difference between AWS Security Groups and Network ACLs (NACLs)?", opts: ["They are functionally identical", "Security Groups are stateful and operate at the instance level; NACLs are stateless and operate at the subnet level", "NACLs are stateful; Security Groups are stateless", "Security Groups only allow outbound traffic"], ans: 1, exp: "Security Groups act as a stateful firewall at the instance/ENI level (return traffic is automatically allowed), while Network ACLs are stateless firewalls applied at the subnet level, requiring explicit rules for both inbound and outbound traffic." },
    { cat: "AWS Networking", q: "Can Security Groups in AWS have explicit 'deny' rules?", opts: ["Yes, you can add both allow and deny rules", "No, Security Groups only support 'allow' rules; anything not explicitly allowed is implicitly denied", "Yes, but only for outbound traffic", "Only in government cloud regions"], ans: 1, exp: "AWS Security Groups only support allow rules — there's no way to explicitly deny traffic; any traffic not matched by an allow rule is implicitly denied." },
    { cat: "AWS Networking", q: "What is a Route Table used for in an AWS VPC?", opts: ["Storing DNS records", "Defining the rules (routes) that determine where network traffic from a subnet or gateway is directed", "Encrypting EBS volumes", "Managing IAM roles"], ans: 1, exp: "A route table contains a set of rules (routes) used to determine where network traffic from associated subnets or gateways should be directed, such as to an Internet Gateway, NAT Gateway, or peering connection." },
    { cat: "AWS Networking", q: "What is VPC Peering in AWS?", opts: ["Connecting a VPC to the public internet", "A networking connection between two VPCs that enables routing traffic between them privately using private IP addresses", "A method of load balancing across regions", "Connecting a VPC to an on-premises data center"], ans: 1, exp: "VPC Peering establishes a direct, private network connection between two VPCs, allowing resources in each to communicate using private IP addresses as if they were on the same network." },
    { cat: "AWS Networking", q: "What limitation does basic VPC Peering have regarding transitive routing?", opts: ["None, it fully supports transitive routing", "VPC Peering connections are not transitive — if VPC A peers with VPC B, and B peers with C, A cannot reach C through B without a direct peering connection", "It only supports IPv6", "It requires a VPN gateway"], ans: 1, exp: "VPC Peering is non-transitive: traffic cannot be routed through an intermediate peered VPC, so each pair of VPCs that needs to communicate must have its own direct peering connection (or use Transit Gateway instead)." },
    { cat: "AWS Networking", q: "What problem does AWS Transit Gateway solve compared to many individual VPC Peering connections?", opts: ["It encrypts data at rest", "It acts as a central hub that simplifies network connectivity between many VPCs and on-premises networks, avoiding a complex full mesh of peering connections", "It replaces Route 53", "It removes the need for security groups"], ans: 1, exp: "AWS Transit Gateway acts as a central hub-and-spoke router, letting many VPCs and on-premises networks connect to it once, instead of requiring a complex full mesh of individual VPC peering connections." },
    { cat: "AWS Networking", q: "What is Amazon Route 53 primarily used for?", opts: ["Virtual machine hosting", "A scalable, highly available DNS web service used for domain registration, DNS routing, and health checking", "Storing object data", "Container orchestration"], ans: 1, exp: "Amazon Route 53 is AWS's DNS web service, providing domain registration, DNS resolution/routing, and health checking to route traffic to healthy endpoints." },
    { cat: "AWS Networking", q: "What is a Route 53 'health check' used for?", opts: ["Checking the health of an IAM role", "Monitoring the health/availability of an endpoint and automatically routing DNS queries away from unhealthy resources", "Encrypting DNS queries", "Validating SSL certificates only"], ans: 1, exp: "Route 53 health checks monitor the health of specified endpoints and can be used with DNS failover routing policies to automatically stop directing traffic to unhealthy resources." },
    { cat: "AWS Networking", q: "What does Amazon CloudFront provide?", opts: ["A relational database service", "A Content Delivery Network (CDN) that caches and delivers content from edge locations close to users for lower latency", "A container registry", "An identity management service"], ans: 1, exp: "Amazon CloudFront is AWS's CDN service, caching and serving content (static and dynamic) from a global network of edge locations to reduce latency for end users." },
    { cat: "AWS Networking", q: "What are the three main types of Elastic Load Balancers (ELB) offered by AWS?", opts: ["Basic, Standard, Premium Load Balancer", "Application Load Balancer (ALB), Network Load Balancer (NLB), and Gateway Load Balancer (GLB)", "Public, Private, Hybrid Load Balancer", "Regional, Global, Edge Load Balancer"], ans: 1, exp: "AWS offers Application Load Balancer (Layer 7, HTTP/HTTPS-aware routing), Network Load Balancer (Layer 4, ultra-high performance TCP/UDP), and Gateway Load Balancer (for deploying/scaling third-party virtual appliances)." },
    { cat: "AWS Networking", q: "Which AWS load balancer type operates at Layer 7 and can route based on URL path or hostname?", opts: ["Network Load Balancer", "Application Load Balancer", "Classic Load Balancer only", "Gateway Load Balancer"], ans: 1, exp: "The Application Load Balancer (ALB) operates at Layer 7 (HTTP/HTTPS), enabling content-based routing decisions such as routing by URL path, hostname, or HTTP headers." },
    { cat: "AWS Networking", q: "Which AWS load balancer type is best suited for extreme performance and handling millions of requests per second at Layer 4?", opts: ["Application Load Balancer", "Network Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, exp: "The Network Load Balancer (NLB) operates at Layer 4 (TCP/UDP), designed for ultra-low latency and extremely high throughput, capable of handling millions of requests per second while preserving the source IP." },
    { cat: "AWS Networking", q: "What is an Elastic IP address in AWS?", opts: ["A temporary IP that changes on every reboot", "A static, public IPv4 address designed for dynamic cloud computing that you can allocate and remap between instances", "An internal-only private IP", "A DNS hostname alias"], ans: 1, exp: "An Elastic IP is a static public IPv4 address that you allocate to your AWS account and can associate with an EC2 instance or network interface, remaining constant even if the underlying instance is stopped and restarted." },
    { cat: "AWS Networking", q: "What is an Elastic Network Interface (ENI) in AWS?", opts: ["A physical network cable", "A virtual network interface that can be attached to an EC2 instance within a VPC, with its own private IP, MAC address, and security groups", "A type of load balancer", "An AWS billing dashboard"], ans: 1, exp: "An ENI is a virtual network interface in a VPC that can include attributes like a primary private IPv4 address, one or more secondary IPs, a MAC address, and security groups, and can be attached/detached from instances." },
    { cat: "AWS Networking", q: "What is AWS Direct Connect used for?", opts: ["Encrypting S3 buckets", "Establishing a dedicated, private network connection from an on-premises data center to AWS, bypassing the public internet", "Connecting two AWS regions over the public internet only", "Managing IAM policies"], ans: 1, exp: "AWS Direct Connect provides a dedicated private network link between an on-premises location and AWS, offering more consistent network performance and reduced bandwidth costs compared to internet-based connections." },
    { cat: "AWS Networking", q: "What is an AWS Site-to-Site VPN used for?", opts: ["Connecting individual remote employee laptops to AWS only", "Creating an encrypted IPsec connection between an on-premises network and an Amazon VPC over the public internet", "Hosting a public website", "Load balancing across regions"], ans: 1, exp: "AWS Site-to-Site VPN creates a secure, encrypted IPsec tunnel between an on-premises network (or another cloud) and a VPC, routed over the public internet." },
    { cat: "AWS Networking", q: "What is the purpose of AWS PrivateLink?", opts: ["To make all VPC resources publicly accessible", "To enable private connectivity between VPCs and AWS services (or third-party services) without traversing the public internet, using private IP addresses", "To replace Route 53 entirely", "To provide free data transfer between regions"], ans: 1, exp: "AWS PrivateLink provides private connectivity between VPCs, AWS services, and supported third-party services using private IPs, so traffic never traverses the public internet." },
    { cat: "AWS Networking", q: "What is a VPC Endpoint in AWS?", opts: ["A physical hardware appliance", "A virtual device that enables private connections between a VPC and supported AWS services without requiring an Internet Gateway or NAT device", "A type of EC2 instance", "A billing alert"], ans: 1, exp: "A VPC Endpoint allows private connections between resources in a VPC and supported AWS services (like S3 or DynamoDB) using AWS's internal network, avoiding the need for internet gateways or NAT devices." },
    { cat: "AWS Networking", q: "What are the two types of VPC Endpoints in AWS?", opts: ["Public and Private Endpoints", "Interface Endpoints (powered by PrivateLink, using an ENI) and Gateway Endpoints (used for S3 and DynamoDB, added as a route table target)", "Free and Paid Endpoints", "Regional and Global Endpoints"], ans: 1, exp: "AWS offers Interface Endpoints, which use an ENI with a private IP as an entry point (powered by PrivateLink), and Gateway Endpoints, which are specifically for S3 and DynamoDB and work by adding a target to the route table." },
    { cat: "AWS Networking", q: "What is the purpose of an AWS Availability Zone (AZ)?", opts: ["A billing region", "One or more discrete, physically isolated data centers within an AWS Region, used for fault tolerance and high availability", "A type of security group", "A VPC subnet type"], ans: 1, exp: "An Availability Zone is one or more discrete data centers with redundant power, networking, and connectivity within an AWS Region; distributing resources across multiple AZs improves fault tolerance." },
    { cat: "AWS Networking", q: "What is the difference between an AWS Region and an Availability Zone?", opts: ["They are the same thing", "A Region is a geographic area containing multiple, isolated Availability Zones; an AZ is a physically separate data center cluster within that Region", "An AZ contains multiple Regions", "Regions only exist in the US"], ans: 1, exp: "An AWS Region is a separate geographic area (e.g. us-east-1) that contains multiple, isolated Availability Zones, each a cluster of physically separate data centers offering fault isolation while remaining close enough for low-latency replication." },
    { cat: "AWS Networking", q: "What is the purpose of AWS WAF (Web Application Firewall)?", opts: ["Encrypting EBS volumes", "Protecting web applications from common exploits (like SQL injection or XSS) by filtering and monitoring HTTP/HTTPS traffic based on configurable rules", "Routing DNS queries", "Managing VPC peering"], ans: 1, exp: "AWS WAF lets you create rules to filter and monitor HTTP/HTTPS requests to protect web applications from common web exploits like SQL injection, cross-site scripting, and bot traffic." },
    { cat: "AWS Networking", q: "What is AWS Shield used for?", opts: ["Database encryption", "A managed service that provides protection against Distributed Denial of Service (DDoS) attacks for applications running on AWS", "Code deployment automation", "Identity federation"], ans: 1, exp: "AWS Shield is a managed DDoS protection service, with a free Standard tier protecting all AWS customers and an Advanced tier offering enhanced protections and 24/7 support for higher-risk applications." },
    { cat: "AWS Networking", q: "What is the function of an AWS API Gateway?", opts: ["A physical network switch", "A fully managed service for creating, publishing, and securing APIs (REST, HTTP, WebSocket) that act as a front door for backend services like Lambda", "An EC2 instance type", "A DNS resolver"], ans: 1, exp: "Amazon API Gateway is a managed service for building, deploying, and securing APIs at scale, acting as the entry point that routes requests to backend services such as AWS Lambda functions, EC2, or other HTTP endpoints." },
    { cat: "AWS Networking", q: "What does AWS API Gateway's support for WebSocket APIs enable?", opts: ["Only REST calls", "Persistent, two-way, real-time communication between clients and backend services such as Lambda, integrated with API Gateway's routing and management features", "Static website hosting only", "Database replication"], ans: 1, exp: "API Gateway WebSocket APIs let you build real-time, bidirectional applications (like chat apps) where API Gateway manages the persistent connections and routes messages to backend integrations like Lambda functions." },
    { cat: "AWS Networking", q: "What is the purpose of a Bastion Host (jump box) in AWS networking?", opts: ["To host a public website", "A hardened EC2 instance in a public subnet used as a secure entry point for administrators to access instances in private subnets via SSH/RDP", "To balance load across AZs", "To cache DNS queries"], ans: 1, exp: "A bastion host is a specially secured instance placed in a public subnet that administrators connect to first, then 'jump' from it to access instances in private subnets, reducing the private network's direct exposure to the internet." },
    { cat: "AWS Networking", q: "What does AWS Global Accelerator improve?", opts: ["S3 storage costs", "Network performance for global applications by routing traffic through AWS's global network infrastructure to the optimal endpoint", "Lambda cold start times only", "IAM policy evaluation speed"], ans: 1, exp: "AWS Global Accelerator uses static anycast IP addresses and AWS's global network backbone to route user traffic to the optimal, healthy application endpoint, improving availability and performance for global users." },
    { cat: "AWS Networking", q: "What is the maximum number of VPCs that can typically be connected efficiently using a hub-and-spoke model via AWS Transit Gateway, compared to full-mesh VPC Peering?", opts: ["Transit Gateway scales much more simply since each VPC only needs one connection to the hub, unlike the quadratic growth of connections required for full-mesh peering", "They scale identically", "Transit Gateway only supports 2 VPCs", "VPC Peering scales better"], ans: 0, exp: "With Transit Gateway, each VPC needs just one attachment to the central hub, so connectivity scales linearly; with full-mesh VPC Peering, the number of required connections grows quadratically as more VPCs are added." },
    { cat: "AWS Networking", q: "What is the purpose of AWS Network Firewall?", opts: ["A physical firewall appliance shipped to your data center", "A managed service providing stateful, network-level firewall and intrusion detection/prevention capabilities for traffic entering and leaving a VPC", "An IAM permission boundary", "A type of load balancer"], ans: 1, exp: "AWS Network Firewall is a managed service that lets you deploy essential network protections, including stateful firewall rules and intrusion detection/prevention, for all traffic entering and exiting your VPCs." },
    { cat: "AWS Networking", q: "In AWS, what is the function of a Route Table's 'local' route?", opts: ["It routes all traffic to the internet", "It is an automatically added route allowing communication between all resources within the VPC's CIDR block", "It routes traffic to AWS support", "It blocks all internal traffic"], ans: 1, exp: "Every VPC route table automatically includes a 'local' route covering the VPC's full CIDR block, enabling resources within the VPC to communicate with each other by default." },
    { cat: "AWS Networking", q: "What does it mean that AWS NACLs evaluate rules in numbered order?", opts: ["Rules are evaluated randomly", "Rules are processed in order of their rule number from lowest to highest, and the first matching rule is applied", "Only the highest-numbered rule applies", "Rule order does not matter for NACLs"], ans: 1, exp: "Network ACL rules are evaluated in order from the lowest rule number to the highest; as soon as a rule matches the traffic, it is applied and evaluation stops, so rule ordering matters." },
    { cat: "AWS Networking", q: "What is the default behavior of a newly created custom Security Group in AWS regarding outbound traffic?", opts: ["All outbound traffic is denied by default", "All outbound traffic is allowed by default until explicitly restricted", "Only HTTPS outbound traffic is allowed", "Outbound traffic requires manual approval per request"], ans: 1, exp: "By default, a new custom Security Group allows all outbound traffic, while inbound traffic is denied until explicit allow rules are added." },
    { cat: "AWS Networking", q: "What AWS service would you use to monitor and log all network traffic (IP traffic metadata) going to and from network interfaces in your VPC?", opts: ["CloudTrail", "VPC Flow Logs", "AWS Config", "CloudWatch Synthetics"], ans: 1, exp: "VPC Flow Logs capture metadata about IP traffic flowing to and from network interfaces in a VPC, useful for troubleshooting connectivity issues and security/traffic analysis." },
    { cat: "AWS Networking", q: "What does AWS Route 53's 'latency-based routing' policy do?", opts: ["Always routes to the cheapest region", "Routes traffic to the AWS region that provides the lowest network latency for the end user", "Routes traffic randomly across all regions", "Encrypts DNS queries based on latency"], ans: 1, exp: "Latency-based routing in Route 53 directs users to the AWS resource/region that offers the best (lowest) network latency for them, based on measured latency between AWS regions and user locations." },
    { cat: "AWS Networking", q: "What does AWS Route 53's 'weighted routing' policy allow?", opts: ["Routing based purely on geographic location", "Distributing traffic across multiple resources in proportions you specify, useful for testing new versions or load distribution", "Encrypting heavier payloads more strongly", "Only routing to the lowest-latency endpoint"], ans: 1, exp: "Weighted routing lets you assign relative weights to multiple resources associated with a domain name, controlling what proportion of traffic each one receives, useful for A/B testing or gradual rollouts." },
    { cat: "AWS Networking", q: "What is the purpose of AWS Route 53 'failover routing'?", opts: ["To always split traffic evenly between two endpoints", "To route traffic to a primary resource while it's healthy, and automatically fail over to a secondary resource if the primary becomes unhealthy", "To delete unhealthy DNS records permanently", "To encrypt failover traffic"], ans: 1, exp: "Failover routing works with Route 53 health checks to send traffic to a primary endpoint under normal conditions, automatically shifting traffic to a designated secondary (backup) endpoint if the primary is detected as unhealthy." },
    { cat: "AWS Networking", q: "What is the difference between an AWS Application Load Balancer and an AWS API Gateway, both of which can route HTTP requests?", opts: ["They are functionally identical with no differences", "ALB is primarily a Layer 7 load balancer for distributing traffic across targets like EC2/containers, while API Gateway adds API-specific features like request validation, throttling, API keys, and direct Lambda integration", "API Gateway only works with UDP", "ALB cannot route to Lambda at all"], ans: 1, exp: "While both can route HTTP(S) traffic, ALB focuses on load balancing across targets (EC2, ECS, Lambda) with content-based routing, whereas API Gateway is purpose-built for API management, offering features like usage plans, API keys, request/response transformation, and built-in throttling." },
];